    const track = getSelectedMetricsTrack();
    if (!track) return null;
    const rows = getRowsForTrack(track.trackId);
    return buildMetricsForTrackRows(track, rows, getMetricsWindowSize(), { getDefaultSampleFrameType }).summary;
